"use client";

import { Message } from "@/types/chat";
import { Badge } from "@/components/ui/badge";
import { AlertTriangle, Bot, User, Zap } from "lucide-react";
import { cn } from "@/lib/utils";

interface MessageBubbleProps {
  message: Message;
}

const TOOL_LABELS: Record<string, string> = {
  search_faq: "FAQ Search",
  search_detailed_faq: "Detailed FAQ",
  reformulate_query: "Query Reformulation",
  get_weather_network_impact: "Weather Check",
  get_country_info: "Country Info",
  validate_phone_number: "Number Validation",
  check_public_holidays: "Holiday Check",
};

export function MessageBubble({ message }: MessageBubbleProps) {
  const isUser = message.role === "user";

  return (
    <div className={cn("flex gap-3 group", isUser && "flex-row-reverse")}>
      {/* Avatar */}
      <div
        className={cn(
          "flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center text-white text-sm font-medium",
          isUser ? "bg-blue-600" : "bg-emerald-600"
        )}
      >
        {isUser ? <User size={16} /> : <Bot size={16} />}
      </div>

      {/* Bubble */}
      <div className={cn("flex flex-col gap-1 max-w-[75%]", isUser && "items-end")}>
        <div
          className={cn(
            "rounded-2xl px-4 py-3 text-sm leading-relaxed",
            isUser
              ? "bg-blue-600 text-white rounded-tr-sm"
              : message.error
              ? "bg-red-50 text-red-800 border border-red-200 rounded-tl-sm"
              : "bg-white text-gray-800 border border-gray-100 shadow-sm rounded-tl-sm"
          )}
        >
          <p className="whitespace-pre-wrap">{message.content}</p>
        </div>

        {/* Metadata row */}
        <div className={cn("flex flex-wrap gap-1.5 px-1", isUser && "justify-end")}>
          {/* Timestamp */}
          <span className="text-xs text-gray-400">
            {message.timestamp.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
          </span>

          {/* Cached badge */}
          {message.cached && (
            <Badge variant="secondary" className="text-xs py-0 h-4 gap-1">
              <Zap size={10} />
              Cached
            </Badge>
          )}

          {/* Escalation flag */}
          {message.escalationFlagged && (
            <Badge variant="destructive" className="text-xs py-0 h-4 gap-1">
              <AlertTriangle size={10} />
              Escalated
            </Badge>
          )}

          {/* Tools used */}
          {message.toolsUsed?.map((tool) => (
            <Badge key={tool} variant="outline" className="text-xs py-0 h-4 text-emerald-700 border-emerald-200 bg-emerald-50">
              {TOOL_LABELS[tool] ?? tool}
            </Badge>
          ))}
        </div>
      </div>
    </div>
  );
}

