import { NextRequest, NextResponse } from "next/server";
import aws4 from "aws4";

const REGION = process.env.AWS_REGION ?? "us-east-1";
const AGENT_ARN = process.env.AGENT_ARN!;
// ARN format: arn:aws:bedrock-agentcore:REGION:ACCOUNT:runtime/AGENT_ID
const AGENT_ID = AGENT_ARN.split("/").pop()!;
const HOST = `bedrock-agentcore-runtime.${REGION}.amazonaws.com`;
const ENDPOINT = `https://${HOST}/runtimes/${AGENT_ID}/invoke`;

export async function POST(req: NextRequest) {
  try {
    const { prompt, actorId, threadId } = await req.json();
    if (!prompt?.trim()) {
      return NextResponse.json({ error: "Prompt is required" }, { status: 400 });
    }

    const body = JSON.stringify({ prompt, actor_id: actorId, thread_id: threadId });

    const opts = aws4.sign(
      {
        host: HOST,
        path: `/runtimes/${AGENT_ID}/invoke`,
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-amzn-bedrock-agentcore-session-id": threadId,
        },
        body,
        service: "bedrock-agentcore",
        region: REGION,
      },
      {
        accessKeyId: process.env.AWS_ACCESS_KEY_ID!,
        secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY!,
        sessionToken: process.env.AWS_SESSION_TOKEN,
      }
    );

    const res = await fetch(ENDPOINT, {
      method: "POST",
      headers: opts.headers as Record<string, string>,
      body,
    });

    const text = await res.text();
    const data = JSON.parse(text);
    return NextResponse.json(data, { status: res.status });
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : "Unknown error";
    console.error("AgentCore error:", message);
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

