"use client";

import { useChatStore } from "@/store/chat";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import {
  MessageSquarePlus, Trash2, Wifi, ChevronLeft, ChevronRight, User, Settings
} from "lucide-react";
import { cn } from "@/lib/utils";
import { formatDistanceToNow } from "date-fns";
import { useState } from "react";

export function Sidebar() {
  const {
    user, sessions, activeSessionId, sidebarOpen,
    createSession, deleteSession, setActiveSession, toggleSidebar, setUser,
  } = useChatStore();

  const [editingName, setEditingName] = useState(false);
  const [nameInput, setNameInput] = useState(user.name);

  return (
    <>
      {/* Collapsed toggle button */}
      {!sidebarOpen && (
        <button
          onClick={toggleSidebar}
          className="fixed left-0 top-1/2 -translate-y-1/2 z-20 bg-white border border-gray-200 rounded-r-lg p-1.5 shadow-sm hover:bg-gray-50"
          aria-label="Open sidebar"
        >
          <ChevronRight size={16} className="text-gray-500" />
        </button>
      )}

      <aside
        className={cn(
          "flex flex-col bg-gray-900 text-white transition-all duration-200 flex-shrink-0",
          sidebarOpen ? "w-64" : "w-0 overflow-hidden"
        )}
      >
        {/* Logo */}
        <div className="flex items-center justify-between px-4 py-4 border-b border-gray-700">
          <div className="flex items-center gap-2">
            <div className="w-7 h-7 rounded-full bg-emerald-500 flex items-center justify-center">
              <Wifi size={14} />
            </div>
            <span className="font-semibold text-sm">Lauki Phones</span>
          </div>
          <button onClick={toggleSidebar} className="text-gray-400 hover:text-white" aria-label="Close sidebar">
            <ChevronLeft size={16} />
          </button>
        </div>

        {/* New chat */}
        <div className="px-3 py-3">
          <Button
            onClick={() => createSession()}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white text-sm gap-2"
            size="sm"
          >
            <MessageSquarePlus size={15} />
            New conversation
          </Button>
        </div>

        <Separator className="bg-gray-700" />

        {/* Sessions */}
        <ScrollArea className="flex-1 px-2 py-2">
          <p className="text-xs text-gray-500 px-2 mb-2 uppercase tracking-wider">Recent</p>
          <div className="space-y-0.5">
            {sessions.map((session) => (
              <div
                key={session.id}
                className={cn(
                  "group flex items-center gap-2 rounded-lg px-2 py-2 cursor-pointer text-sm transition-colors",
                  session.id === activeSessionId
                    ? "bg-gray-700 text-white"
                    : "text-gray-300 hover:bg-gray-800"
                )}
                onClick={() => setActiveSession(session.id)}
              >
                <MessageSquarePlus size={14} className="flex-shrink-0 text-gray-400" />
                <div className="flex-1 min-w-0">
                  <p className="truncate text-xs font-medium">{session.title}</p>
                  <p className="text-xs text-gray-500">
                    {formatDistanceToNow(new Date(session.updatedAt), { addSuffix: true })}
                  </p>
                </div>
                <button
                  onClick={(e) => { e.stopPropagation(); deleteSession(session.id); }}
                  className="opacity-0 group-hover:opacity-100 text-gray-500 hover:text-red-400 transition-opacity flex-shrink-0"
                  aria-label="Delete session"
                >
                  <Trash2 size={13} />
                </button>
              </div>
            ))}
          </div>
        </ScrollArea>

        <Separator className="bg-gray-700" />

        {/* User profile */}
        <div className="px-3 py-3">
          {editingName ? (
            <form onSubmit={(e) => {
              e.preventDefault();
              setUser({ ...user, name: nameInput || "Guest" });
              setEditingName(false);
            }} className="flex gap-2">
              <input
                autoFocus
                value={nameInput}
                onChange={(e) => setNameInput(e.target.value)}
                className="flex-1 bg-gray-800 text-white text-xs rounded px-2 py-1 border border-gray-600 focus:outline-none focus:border-emerald-500"
                maxLength={30}
              />
              <Button type="submit" size="sm" className="h-6 text-xs px-2 bg-emerald-600 hover:bg-emerald-700">Save</Button>
            </form>
          ) : (
            <div className="flex items-center gap-2">
              <Avatar className="w-7 h-7">
                <AvatarFallback className="bg-emerald-700 text-white text-xs">
                  {user.name.charAt(0).toUpperCase()}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-medium truncate">{user.name}</p>
                <p className="text-xs text-gray-500">Customer</p>
              </div>
              <button onClick={() => { setNameInput(user.name); setEditingName(true); }}
                className="text-gray-500 hover:text-white" aria-label="Edit name">
                <Settings size={13} />
              </button>
            </div>
          )}
        </div>
      </aside>
    </>
  );
}

