"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { v4 as uuidv4 } from "uuid";
import { Send, Wifi } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { MessageBubble } from "@/components/MessageBubble";
import { TypingIndicator } from "@/components/TypingIndicator";
import { useChatStore } from "@/store/chat";
import { Message, ChatResponse } from "@/types/chat";

const SUGGESTIONS = [
  "How do I activate roaming?",
  "My signal is bad in Mumbai",
  "I want to port number +919876543210",
  "When will my dispute be resolved?",
];

const WELCOME: Message = {
  id: "welcome",
  role: "assistant",
  content: "Hi! I'm Lauki Phones AI Assistant. I can help you with plans, billing, network issues, roaming, and more. How can I help you today?",
  timestamp: new Date(),
};

export function ChatPanel() {
  const { user, activeSessionId, getActiveSession, addMessage } = useChatStore();
  const session = getActiveSession();
  const messages = session?.messages ?? [];

  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isLoading]);

  // Reset input when session changes
  useEffect(() => {
    setInput("");
    setIsLoading(false);
    inputRef.current?.focus();
  }, [activeSessionId]);

  const sendMessage = useCallback(async (text: string) => {
    const trimmed = text.trim();
    if (!trimmed || isLoading) return;

    const userMsg: Message = {
      id: uuidv4(), role: "user", content: trimmed, timestamp: new Date(),
    };
    addMessage(activeSessionId, userMsg);
    setInput("");
    setIsLoading(true);

    try {
      const res = await fetch("/api/chat", {
